using System.ComponentModel;
using System.Net.Http.Headers;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

// ── Services ───────────────────────────────────────────────────
var services = new ServiceCollection()
    .AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning))
    .BuildServiceProvider();

var loggerFactory = services.GetRequiredService<ILoggerFactory>();

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ── Tools ──────────────────────────────────────────────────────
var notepad = new Notepad();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.Add(
    new ProductInfoHeaderValue("ResearchAgent", "1.0"));
var webSearch = new WebSearch(httpClient);

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notepad.SaveNote),
    AIFunctionFactory.Create(notepad.GetAllNotes),
};

// ── Agent ──────────────────────────────────────────────────────
var instructions = """
    You are a research agent. Your job is to thoroughly research a topic
    using the tools available to you, then produce a well-organized summary.

    Follow this workflow:
    1. Use search_web to find relevant information (run multiple searches
       with different queries to get broad coverage).
    2. Use fetch_page to read promising pages from the search results.
    3. Use save_note to record key findings as you go — include the source URL.
    4. After gathering enough information, use get_all_notes to review
       everything you've collected.
    5. Produce a final, well-structured summary with sections, key facts,
       and source references.

    Be thorough but concise. Aim for 3-5 searches to cover the topic well.
    """;

var agent = new ChatClientAgent(
    chatClient: chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes",
    tools: tools,
    loggerFactory: loggerFactory,
    services: services);

var session = await agent.CreateSessionAsync(CancellationToken.None);

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0.2f,
        MaxOutputTokens = 4096,
    },
};

Console.WriteLine($"\n🔍 Researching: {topic}\n");

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine("\n\n✅ Research complete.");

// ── Tool Implementations ───────────────────────────────────────

/// <summary>Web search tool using DuckDuckGo and direct page fetching.</summary>
sealed class WebSearch(HttpClient httpClient)
{
    [Description("Search the web for information on a topic. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await httpClient.GetStringAsync(url);
            var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract (instant answer)
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrEmpty(abstractText))
            {
                results.Add($"**Instant Answer**: {abstractText}\nSource: {abstractUrl}");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var related))
            {
                foreach (var item in related.EnumerateArray().Take(8))
                {
                    if (item.TryGetProperty("Text", out var text) &&
                        item.TryGetProperty("FirstURL", out var itemUrl))
                    {
                        results.Add($"- {text.GetString()}\n  URL: {itemUrl.GetString()}");
                    }
                }
            }

            return results.Count > 0
                ? $"Search results for '{query}':\n\n{string.Join("\n\n", results)}"
                : $"No direct results found for '{query}'. Try rephrasing or use fetch_page with a specific URL.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query or use fetch_page directly.";
        }
    }

    [Description("Fetch and read the text content of a web page. Use this to get detailed information from a URL found during search.")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL to fetch")] string url)
    {
        try
        {
            var response = await httpClient.GetAsync(url);
            response.EnsureSuccessStatusCode();
            var html = await response.Content.ReadAsStringAsync();

            // Strip HTML tags for a rough text extraction
            var text = System.Text.RegularExpressions.Regex.Replace(html, "<script[^>]*>[\\s\\S]*?</script>", " ");
            text = System.Text.RegularExpressions.Regex.Replace(text, "<style[^>]*>[\\s\\S]*?</style>", " ");
            text = System.Text.RegularExpressions.Regex.Replace(text, "<[^>]+>", " ");
            text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ");
            text = System.Net.WebUtility.HtmlDecode(text).Trim();

            const int maxLength = 6000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "... [truncated]";

            return $"Content from {url}:\n\n{text}";
        }
        catch (Exception ex)
        {
            return $"Failed to fetch {url}: {ex.Message}";
        }
    }
}

/// <summary>In-memory note-taking tool for recording research findings.</summary>
sealed class Notepad
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Save a research note. Use this to record key findings, facts, or quotes as you research. Include the source URL when possible.")]
    public string SaveNote(
        [Description("A short title for the note")] string title,
        [Description("The content of the note, including facts and source URLs")] string content)
    {
        _notes.Add((title, content));
        return $"✅ Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes. Use this before writing your final summary to review everything you've collected.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet. Use save_note to record findings.";

        var result = $"📋 All research notes ({_notes.Count} total):\n\n";
        for (int i = 0; i < _notes.Count; i++)
        {
            result += $"--- Note #{i + 1}: {_notes[i].Title} ---\n{_notes[i].Content}\n\n";
        }
        return result;
    }
}

