var loggerFactory = services.GetRequiredService<ILoggerFactory>();

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ── Tools ──────────────────────────────────────────────────────
var notepad = new Notepad();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.Add(
    new ProductInfoHeaderValue("ResearchAgent", "1.0"));
var webSearch = new WebSearch(httpClient);

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notepad.SaveNote),
    AIFunctionFactory.Create(notepad.GetAllNotes),
};

